import{_ as o,Z as a,P as r,g as s,k as l,m as t}from"./chunks/framework.Dp5g00Bf.js";const _=JSON.parse('{"title":"ubuntu共享桌面","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/ubuntu共享桌面/index.md","filePath":"views/1-开发🌏/3-运维/ubuntu共享桌面/index.md","lastUpdated":1778336291000}'),u={name:"views/1-开发🌏/3-运维/ubuntu共享桌面/index.md"};function d(p,e,h,c,m,b){const i=a("NolebaseGitContributors"),n=a("NolebaseGitChangelog");return r(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[e[0]||(e[0]=l('<h1 id="ubuntu共享桌面" tabindex="-1">ubuntu共享桌面 <a class="header-anchor" href="#ubuntu共享桌面" aria-label="Permalink to &quot;ubuntu共享桌面&quot;">​</a></h1><p>当我们使用ubuntu桌面版的时候，我们一定希望可以使用别的电脑远程该服务器并使用它的图形化页面。但是众所周知</p><p>操作系统图形化页面的显示需要显示器，这一点我们可以用淘宝几块钱一个的HDMI插头替代。</p><h2 id="一、将密钥环密码置空" tabindex="-1">一、<strong>将密钥环密码置空！</strong> <a class="header-anchor" href="#一、将密钥环密码置空" aria-label="Permalink to &quot;一、**将密钥环密码置空！**&quot;">​</a></h2><p>该密钥环会导致我们的共享桌面重启自动登录后，桌面共享服务（如 VNC 或远程桌面）在系统启动时比密钥环更早加载，而密钥环此时尚未解锁，服务将无法读取存储的密码，从而生成一个新的随机密码，如果用户免密自动登录的情况下，我们重启服务器会无法使用远程桌面。因此如果对安全要求不是特别高的情况下，建议为空，这样的话我们后面可以直接一条龙启动远程桌面。</p><p><strong>图形化页面的终端输入 <code>seahorse</code></strong></p><ul><li>找到默认密钥环（通常显示为“登录”或“Login”），右键选择“更改密码”。</li><li>输入当前用户密码，将新密码留空，点击“继续”。</li><li>重启系统后，在桌面共享设置中重新设置密码。</li></ul><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260221160429726.avif" alt=""></p><h2 id="二、在设置中打开桌面共享" tabindex="-1">二、在设置中打开桌面共享 <a class="header-anchor" href="#二、在设置中打开桌面共享" aria-label="Permalink to &quot;二、在设置中打开桌面共享&quot;">​</a></h2><p>在系统设置里的远程共享打开远程桌面，将桌面共享与远程控制设置为打开，并设置好用户名和密码。</p><h2 id="三、启动用户自动登录" tabindex="-1">三、启动用户自动登录 <a class="header-anchor" href="#三、启动用户自动登录" aria-label="Permalink to &quot;三、启动用户自动登录&quot;">​</a></h2><p>按要求解锁并输入完密码后，可实现重启系统自动登录。</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260221161050966.avif" alt=""></p><h2 id="四、熄屏改为从不-电源改为性能" tabindex="-1">四、熄屏改为从不，电源改为性能 <a class="header-anchor" href="#四、熄屏改为从不-电源改为性能" aria-label="Permalink to &quot;四、熄屏改为从不，电源改为性能&quot;">​</a></h2><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260221161220023.avif" alt=""></p>',15)),t(i),t(n)])}const f=o(u,[["render",d]]);export{_ as __pageData,f as default};
